type CurrentSession = {
  user: {
    id: UserId
    email: string
    displayName: string
  }
  account: {
    id: AccountId
    plan: AccountPlan
  }
  roles: UserRole[]
  permissions: PermissionKey[]
  preferences: {
    theme: ThemePreference
    locale: Locale
  }
}

export const getCurrentSession = async (): Promise<CurrentSession | null> => {
  const session = await sessionRepository.getFromCookies()
  if (!session) return null

  return authGateway.fetchCurrentSession(session)
}
